import{_ as t,o as a,c as e,Q as i}from"./chunks/framework.b67c47e6.js";const u=JSON.parse('{"title":"MTF File (Roof Framing)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/machine_files/formats/frame_mtf/index.md","filePath":"guide/machine_files/formats/frame_mtf/index.md","lastUpdated":1773939149000}'),n={name:"guide/machine_files/formats/frame_mtf/index.md"},r=i('<h1 id="mtf-file-roof-framing" tabindex="-1">MTF File (Roof Framing) <a class="header-anchor" href="#mtf-file-roof-framing" aria-label="Permalink to &quot;MTF File (Roof Framing)&quot;">​</a></h1><p>The MTF format generates assembly instructions for H&amp;M roof framing machines, including clamp positioning, table layouts, and beam assignments.</p><nav class="table-of-contents"><ul><li><a href="#output">Output</a></li><li><a href="#file-contents">File Contents</a></li><li><a href="#parameters">Parameters</a><ul><li><a href="#clamp-ranges">Clamp Ranges</a></li></ul></li></ul></nav><h2 id="output" tabindex="-1">Output <a class="header-anchor" href="#output" aria-label="Permalink to &quot;Output&quot;">​</a></h2><ul><li><strong>Format:</strong> ZIP containing <code>.mtf</code> files and SVG layout visualizations</li><li><strong>Target machines:</strong> H&amp;M Roof Frame machines</li></ul><h2 id="file-contents" tabindex="-1">File Contents <a class="header-anchor" href="#file-contents" aria-label="Permalink to &quot;File Contents&quot;">​</a></h2><p>Each MTF file contains:</p><ul><li>Table and clamp layout definitions</li><li>Beam positioning and assignments to clamps</li><li>Field descriptions for each table</li><li>SVG visualization of the assembly layout</li></ul><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><table><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Machine max X</strong></td><td>Maximum machine length in mm.</td><td>6000</td></tr><tr><td><strong>Number of tables</strong></td><td>How many assembly tables the machine has.</td><td>4</td></tr><tr><td><strong>Clamps per table</strong></td><td>Number of clamps on each table.</td><td>7</td></tr><tr><td><strong>Min clamp distance</strong></td><td>Minimum distance between clamps in mm.</td><td>300</td></tr><tr><td><strong>Start offset</strong></td><td>Offset from machine start position in mm.</td><td>100</td></tr></tbody></table><h3 id="clamp-ranges" tabindex="-1">Clamp Ranges <a class="header-anchor" href="#clamp-ranges" aria-label="Permalink to &quot;Clamp Ranges&quot;">​</a></h3><p>Define the positioning range for each clamp:</p><table><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td><strong>Start (mm)</strong></td><td>Minimum position for this clamp.</td></tr><tr><td><strong>End (mm)</strong></td><td>Maximum position for this clamp.</td></tr></tbody></table>',13),o=[r];function s(l,m,d,c,h,f){return a(),e("div",null,o)}const g=t(n,[["render",s]]);export{u as __pageData,g as default};
